// ── BTC 月内触碰价位策略（Barrier Touch Relative Value） ──
// questionType: 'hit' → bsOneTouch baseline

const logit   = (p) => Math.log(p / (1 - p));
const sigmoid = (x) => 1 / (1 + Math.exp(-x));
const clamp   = (p, lo=1e-6, hi=1-1e-6) => Math.min(Math.max(p, lo), hi);

// ── 1. Event-scope features ────────────────────────────────
const closes = ctx.underlying.klines.map(k => k.close);
const highs  = ctx.underlying.klines.map(k => k.high);
const lows   = ctx.underlying.klines.map(k => k.low);
const spot   = ctx.underlying.price;

const rsiVal   = ctx.helpers.rsi(closes, 14);
const emaFast  = ctx.helpers.emaArray(closes, 12).at(-1);
const emaSlow  = ctx.helpers.emaArray(closes, 26).at(-1);

const recent3dHigh = Math.max(...highs.slice(-72));
const recent3dLow  = Math.min(...lows.slice(-72));

let volRatio = 1;
try { volRatio = ctx.helpers.volRatio(ctx, '24h', '7d'); } catch(e) {}

// ── TrendScore (-2 to +2) ──────────────────────────────────
let trendScore = 0;
if (rsiVal > 60)              trendScore += 0.5;
if (rsiVal < 40)              trendScore -= 0.5;
if (emaFast > emaSlow)        trendScore += 0.5;
if (emaFast < emaSlow)        trendScore -= 0.5;
if (spot > recent3dHigh)      trendScore += 0.5;
if (spot < recent3dLow)       trendScore -= 0.5;
if (volRatio > 1.3)           trendScore += Math.sign(trendScore) * 0.5 || 0.5;
trendScore = Math.max(-2, Math.min(2, trendScore));

// ── 2. Sort markets for monotonicity check ─────────────────
const activeMarkets = ctx.markets.filter(m => m.strike != null && !m.closed);
const upperMarkets  = activeMarkets.filter(m => m.strike > spot).sort((a,b)=>a.strike-b.strike);
const lowerMarkets  = activeMarkets.filter(m => m.strike < spot).sort((a,b)=>b.strike-a.strike);

// Helper: get Yes price directly from outcomes array
const getYesPrice = (market) => {
  const o = market.outcomes.find(o => String(o.label ?? '').toLowerCase() === 'yes');
  return o ? o.price : null;
};
const getNoPrice = (market) => {
  const o = market.outcomes.find(o => String(o.label ?? '').toLowerCase() === 'no');
  return o ? o.price : null;
};
const getYesBid  = (market) => {
  const o = market.outcomes.find(o => String(o.label ?? '').toLowerCase() === 'yes');
  return o ? o.bestBid : null;
};
const getYesAsk  = (market) => {
  const o = market.outcomes.find(o => String(o.label ?? '').toLowerCase() === 'yes');
  return o ? o.bestAsk : null;
};

// Monotonicity adjacency: is this market Yes price cheap vs neighbours?
const isStructurallyCheap = (market, sortedGroup) => {
  const idx = sortedGroup.findIndex(m => m.slug === market.slug);
  if (idx < 0) return false;
  const mp = getYesPrice(market);
  if (mp == null) return false;
  const prev = idx > 0 ? getYesPrice(sortedGroup[idx-1]) : null;
  const next = idx < sortedGroup.length-1 ? getYesPrice(sortedGroup[idx+1]) : null;
  const cheapVsNext = next != null && mp < next - 0.02;
  const cheapVsPrev = prev != null && mp < prev * 0.55;
  return cheapVsNext || cheapVsPrev;
};

// ── 3. Per-market analysis ────────────────────────────────
const YES_EDGE_THR = 0.06;
const NO_EDGE_THR  = 0.04;

return ctx.markets.map(market => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: 'hold', reason: '已关闭或到期' };
    }
    if (market.strike == null) {
      return { question: market.question, decision: 'hold', reason: 'strike 未知' };
    }

    const mCtx = { market, underlying: ctx.underlying, timing: ctx.timing };

    // Direct outcome price access
    const mktYes = getYesPrice(market);
    const mktNo  = getNoPrice(market);
    const yesBid = getYesBid(market);
    const yesAsk = getYesAsk(market);

    if (mktYes == null) return { question: market.question, decision: 'hold', reason: 'Yes 价格缺失' };

    // ── Filters ──────────────────────────────────────────
    const spreadPct = (yesAsk != null && yesBid != null) ? (yesAsk - yesBid) : 0;
    if (market.liquidity < 100000)
      return { question: market.question, decision: 'hold', reason: `流动性不足 $${(market.liquidity/1000).toFixed(0)}k` };
    if (market.volume < 150000)
      return { question: market.question, decision: 'hold', reason: `成交量不足 $${(market.volume/1000).toFixed(0)}k` };
    if (spreadPct > 0.03)
      return { question: market.question, decision: 'hold', reason: `价差过大 ${(spreadPct*100).toFixed(1)}%` };
    if (mktYes < 0.03 || mktYes > 0.85)
      return { question: market.question, decision: 'hold', reason: `Yes价格越界 ${(mktYes*100).toFixed(1)}%` };

    // ── Distance zone ────────────────────────────────────
    const pctDist  = Math.abs((market.strike - spot) / spot);
    const zone     = pctDist < 0.06 ? 'near' : pctDist < 0.14 ? 'mid' : 'far';
    const isUpper  = market.strike > spot;
    const sortedGroup = isUpper ? upperMarkets : lowerMarkets;

    // ── Baseline: bsOneTouch ─────────────────────────────
    let pYes0;
    try { pYes0 = ctx.helpers.bsOneTouch(mCtx); }
    catch(e) { return { question: market.question, decision: 'hold', reason: `定价失败: ${e}` }; }

    // ── Trend adjustment in log-odds space ───────────────
    const trendDir  = isUpper ? 1 : -1;
    const maxShift  = zone === 'near' ? 0.08 : zone === 'mid' ? 0.05 : 0.03;
    // Convert maxShift (probability domain) to logit units scaled by trend intensity
    const trendShift = trendDir * (trendScore / 2) * logit(clamp(0.5 + maxShift)) * 2;

    const pYesAdj = sigmoid(logit(clamp(pYes0)) + trendShift);

    // ── Probs & edges via helper ─────────────────────────
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYesAdj);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);

    // Find Yes/No edges by outcome index alignment
    // probs[0] aligns to outcomes[0], probs[1] to outcomes[1]
    const yesOutcomeIdx = market.outcomes.findIndex(o => String(o.label??'').toLowerCase()==='yes');
    const noOutcomeIdx  = yesOutcomeIdx === 0 ? 1 : 0;
    const yesEdgeObj    = edges[yesOutcomeIdx];
    const noEdgeObj     = edges[noOutcomeIdx];

    const modelYes = pYesAdj;
    const modelNo  = 1 - pYesAdj;
    const yesAdv   = modelYes - mktYes;
    const noAdv    = modelNo  - (mktNo ?? 1 - mktYes);

    // ── Signal rules ─────────────────────────────────────
    const canBuyYes = (
      (zone === 'near' || zone === 'mid') &&
      yesAdv >= YES_EDGE_THR &&
      (isUpper ? trendScore >= 0 : trendScore <= 0) &&
      isStructurallyCheap(market, sortedGroup)
    );

    const canBuyNo = (
      (zone === 'mid' || zone === 'far') &&
      noAdv >= NO_EDGE_THR &&
      !(zone === 'near' && Math.abs(trendScore) >= 1)
    );

    const hoursLeft = market.hoursToExpiry;
    const timeDecayNo = (zone === 'far' && hoursLeft <= 168 && noAdv >= 0.03) ||
                        (zone === 'mid' && hoursLeft <= 72  && noAdv >= 0.03);

    let decision = 'hold', side = null, edge = 0, reason = '';

    if (canBuyYes && (yesEdgeObj?.edge ?? 0) >= YES_EDGE_THR) {
      decision = 'buy'; side = 'Yes'; edge = yesEdgeObj.edge;
      reason = `近/中端顺势Yes，模型-市场=${(yesAdv*100).toFixed(1)}%，zone=${zone}，TrendScore=${trendScore.toFixed(1)}`;
    } else if ((canBuyNo || timeDecayNo) && (noEdgeObj?.edge ?? 0) >= NO_EDGE_THR) {
      decision = 'buy'; side = 'No'; edge = noEdgeObj.edge;
      reason = timeDecayNo && !canBuyNo
        ? `时间衰减No（${hoursLeft.toFixed(0)}h剩余），优势=${(noAdv*100).toFixed(1)}%`
        : `中远端No，模型优势=${(noAdv*100).toFixed(1)}%，zone=${zone}`;
    } else {
      reason = yesAdv > 0 && yesAdv < YES_EDGE_THR ? `Yes优势不足 ${(yesAdv*100).toFixed(1)}% < 6%` :
               noAdv > 0 && noAdv < NO_EDGE_THR    ? `No优势不足 ${(noAdv*100).toFixed(1)}% < 4%` :
               zone === 'far' && yesAdv > 0         ? '远端拒绝买Yes' :
               !isStructurallyCheap(market, sortedGroup) ? '结构定价合理，无错价' :
               `无显著优势（Yes=${(yesAdv*100).toFixed(1)}%, No=${(noAdv*100).toFixed(1)}%）`;
    }

    return {
      question: market.question,
      strike: market.strike,
      zone,
      hoursToExpiry: Math.round(hoursLeft),
      mktYes: parseFloat((mktYes*100).toFixed(1)),
      modelYes: parseFloat((pYes0*100).toFixed(1)),
      modelYesAdj: parseFloat((pYesAdj*100).toFixed(1)),
      yesAdv: parseFloat((yesAdv*100).toFixed(1)),
      noAdv: parseFloat((noAdv*100).toFixed(1)),
      trendScore,
      decision,
      side,
      edge: parseFloat((edge*100).toFixed(2)),
      reason,
    };
  } catch(err) {
    return { question: market.question, decision: 'hold', reason: String(err) };
  }
});
